这是一个可能的函数实现，使用C++语言：

```c++
#include<bits/stdc++.h>
using namespace std;

bool isAnagram(string str1, string str2){
    // 如果两个字符串的长度不相等，返回false
    if(str1.length()!=str2.length()) return false;
    // 对两个字符串进行排序
    sort(str1.begin(), str1.end());
    sort(str2.begin(), str2.end());
    // 如果两个排序后的字符串相等，返回true
    if(str1==str2) return true;
    // 如果不相等，返回false
    else return false;
}

int main()
{
    string str1 = "anagram";
    string str2 = "nagaram";
    if(isAnagram(str1, str2)) cout<<"Yes, they are anagrams."<<endl;
    else cout<<"No, they are not anagrams."<<endl;

    return 0;
}
```

上面的函数首先判断两个字符串的长度是否相等，如果不相等，直接返回false。然后对两个字符串进行排序，最后判断排序后的两个字符串是否相等，如果相等则返回true，否则返回false。
